def show_context(start, end, width=30):
    s = max(0, start - width)
    e = min(len(raw_text), end + width)
    print(raw_text[s:start] + ">>>" + raw_text[start:end] + "<<<" + raw_text[end:e])

for occ in occurrences_sorted:
    show_context(*occ[:2], width=40)

# Build the expected JSON structure
citations = []
for start, end, text, typ in occurrences_sorted:
    # Sanity check
    assert raw_text[start:end] == text
    citations.append({
        "span_start": start,
        "span_end": end,
        "span_text": text,
        "citation_type": "Aya" if typ == "Aya" else "Hadeeth"
    })

json_output = {"citations": citations}
print(json.dumps(json_output, ensure_ascii=False, indent=2))
